// // This module implements a 4-bit synchronous down-counter with enable and active-high reset.
module sync_up_counter (
    input clk,
    input rst_n,
    input en,
    output reg [3:0] count
);

always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
        count <= 4'b0000;
    else if (en)
        count <= count + 1;
end

endmodule
